const body = $input.first().json.body;
if (!body.bookingId || !body.token) {
  return [{ json: { valid: false, error: 'Missing required fields: bookingId, token' } }];
}
return [{ json: { valid: true, ...body } }];

const booking = $('Find Booking').first().json;
const input = $('Validate').first().json;

if (booking.Status === 'cancelled') {
  return [{ json: { canCancel: false, error: 'This booking is already cancelled' } }];
}

// Parse witness calendar event IDs if present
let witnessCalEventIds = [];
try { witnessCalEventIds = booking.Witness_Calendar_Event_IDs ? JSON.parse(booking.Witness_Calendar_Event_IDs) : []; } catch(e) { witnessCalEventIds = []; }

const staffId = booking.Staff ? booking.Staff[0] : null;
return [{ json: { canCancel: true, bookingRecordId: booking.id, calEventId: booking.Calendar_Event_ID, zoomMeetingId: booking.Zoom_Meeting_ID || '', witnessCalEventIds, staffId, reason: input.reason || '', bookingId: booking.Booking_ID } }];

// v4 — wrapped in top-level try/catch for safety
try {
  const http = this.helpers.httpRequest;
  const status = $('Check Status').first().json;
  const staff = $('Get Staff').first().json;
  const graphToken = $('Get Graph Token').first().json.access_token;
  const msUserId = staff.MS_User_ID;

  // Delete primary calendar event
  if (status.calEventId && msUserId) {
    try {
      await http({
        method: 'DELETE',
        url: `https://graph.microsoft.com/v1.0/users/${msUserId}/events/${status.calEventId}`,
        headers: { Authorization: `Bearer ${graphToken}` },
        returnFullResponse: true
      });
    } catch(e) { /* ignore deletion errors */ }
  }

  // Delete Zoom meeting if applicable
  if (status.zoomMeetingId) {
    try {
      const tokenData = await http({
        method: 'POST',
        url: 'https://zoom.us/oauth/token?grant_type=account_credentials&account_id=' + $vars.ZOOM_ACCOUNT_ID,
        headers: { Authorization: 'Basic ' + Buffer.from($vars.ZOOM_CLIENT_ID + ':' + $vars.ZOOM_CLIENT_SECRET).toString('base64'), 'Content-Type': 'application/x-www-form-urlencoded' },
        json: true
      });
      await http({
        method: 'DELETE',
        url: `https://api.zoom.us/v2/meetings/${status.zoomMeetingId}`,
        headers: { Authorization: `Bearer ${tokenData.access_token}` },
        returnFullResponse: true
      });
    } catch(e) { /* ignore deletion errors */ }
  }

  // Delete witness calendar events if any
  if (status.witnessCalEventIds && status.witnessCalEventIds.length > 0) {
    for (const wEvt of status.witnessCalEventIds) {
      try {
        if (wEvt.calEventId && wEvt.msUserId) {
          await http({
            method: 'DELETE',
            url: `https://graph.microsoft.com/v1.0/users/${wEvt.msUserId}/events/${wEvt.calEventId}`,
            headers: { Authorization: `Bearer ${graphToken}` },
            returnFullResponse: true
          });
        }
      } catch(e) { /* ignore */ }
    }
  }
} catch(topErr) {
  // Top-level catch — log but do not throw
}

return [{ json: { done: true } }];

